```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Healthcare Survey for Rewards</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Arial', sans-serif;
        }

        body {
            background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
            min-height: 100vh;
        }

       .header {
            text-align: center;
            padding: 2rem;
            background: rgba(0, 0, 0, 0.2);
            color: white;
        }

       .hero {
            text-align: center;
            padding: 4rem 0;
        }

       .hero h1 {
            font-size: 2.5rem;
            margin-bottom: 1rem;
        }

       .hero p {
            font-size: 1.2rem;
            margin-bottom: 2rem;
        }

       .cta-button {
            display: inline-block;
            padding: 1rem 2rem;
            background: #3498db;
            color: white;
            text-decoration: none;
            border-radius: 5px;
            font-weight: bold;
        }

       .cta-button:hover {
            background: #2980b9;
        }

